CREATE TABLE IF NOT EXISTS technical_resource_folders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  slug VARCHAR(255) NOT NULL,
  description TEXT,
  icon VARCHAR(50) DEFAULT 'folder',
  sortOrder INT NOT NULL DEFAULT 0,
  parentId INT,
  createdBy INT NOT NULL,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP NOT NULL,
  INDEX tr_folder_slug_idx (slug),
  INDEX tr_folder_parent_idx (parentId)
);

ALTER TABLE technical_resources ADD COLUMN IF NOT EXISTS fileName VARCHAR(500) AFTER fileUrl;
ALTER TABLE technical_resources ADD COLUMN IF NOT EXISTS fileSize INT AFTER fileName;
