ALTER TABLE technical_resources ADD COLUMN IF NOT EXISTS folderId INT AFTER category;
ALTER TABLE technical_resources ADD COLUMN IF NOT EXISTS downloadCount INT NOT NULL DEFAULT 0 AFTER viewCount;
ALTER TABLE technical_resources ADD INDEX IF NOT EXISTS tr_folder_id_idx (folderId);

